5	namespace App\Console\Commands;
6	
7	use Illuminate\Console\Command;
8	use Illuminate\Support\Facades\DB;
9	use Illuminate\Support\Facades\Log;
10	
11	class ReconcilePaymentsCommand extends Command
12	{
13	    protected $signature = 'harborbite:reconcile-payments';
14	    protected $description = 'Detect stuck payment states and create incident tickets';
15	
16	    public function handle(): int
17	    {
18	        $this->info('Reconciling payments...');
19	
20	        // Find orders that are "served" with confirmed payment but not settled
21	        $stuckOrders = DB::table('orders')
22	            ->join('payment_intents', 'orders.id', '=', 'payment_intents.order_id')
23	            ->where('orders.status', 'served')
24	            ->where('payment_intents.status', 'confirmed')
25	            ->select('orders.id as order_id', 'payment_intents.id as payment_intent_id')
26	            ->get();
27	
28	        foreach ($stuckOrders as $stuck) {
29	            $exists = DB::table('incident_tickets')
30	                ->where('order_id', $stuck->order_id)
31	                ->where('type', 'paid_not_settled')
32	                ->where('status', 'open')
33	                ->exists();
34	
35	            if (!$exists) {
36	                DB::table('incident_tickets')->insert([
37	                    'order_id' => $stuck->order_id,
38	                    'payment_intent_id' => $stuck->payment_intent_id,
39	                    'type' => 'paid_not_settled',
40	                    'status' => 'open',
41	                    'created_at' => now(),
42	                    'updated_at' => now(),
43	                ]);
44	
45	                Log::warning('reconciliation', [
46	                    'type' => 'paid_not_settled',
47	                    'order_id' => $stuck->order_id,
48	                    'payment_intent_id' => $stuck->payment_intent_id,
49	                ]);
50	
51	                // Create admin alert for dashboard visibility
52	                DB::table('admin_alerts')->insert([
53	                    'type' => 'paid_not_settled',
54	                    'severity' => 'warning',
55	                    'message' => "Order #{$stuck->order_id} has confirmed payment but is not settled.",
56	                    'threshold_value' => null,
57	                    'actual_value' => null,
58	                    'created_at' => now(),
59	                    'updated_at' => now(),
60	                ]);
61	
62	                $this->line("  Created ticket + alert for order #{$stuck->order_id}");
63	            }
64	        }
65	
66	        // Find expired payment intents that are still pending
67	        $expired = DB::table('payment_intents')
68	            ->where('status', 'pending')
69	            ->where('expires_at', '<', now())
70	            ->get();
71	
72	        foreach ($expired as $intent) {
73	            DB::table('payment_intents')
74	                ->where('id', $intent->id)
75	                ->update(['status' => 'failed', 'updated_at' => now()]);
76	
77	            $this->line("  Expired intent #{$intent->id} for order #{$intent->order_id}");
78	        }
79	
80	        $this->info('Reconciliation complete.');
81	        return self::SUCCESS;
82	    }
83	}
