5	namespace App\Livewire\Manager;
6	
7	use Illuminate\Support\Facades\Crypt;
8	use Illuminate\Support\Facades\DB;
9	use Livewire\Component;
10	
11	class ReconciliationQueue extends Component
12	{
13	    public array $tickets = [];
14	    public string $filterStatus = 'open';
15	
16	    // Resolve form
17	    public ?int $resolvingTicketId = null;
18	    public string $reasonCode = 'cash_verified';
19	    public string $receiptReference = '';
20	
21	    public ?string $message = null;
22	    public ?string $error = null;
23	
24	    public array $reasonCodes = [
25	        'cash_verified' => 'Cash Verified',
26	        'card_receipt_matched' => 'Card Receipt Matched',
27	        'pos_system_confirmed' => 'POS System Confirmed',
28	        'other' => 'Other',
29	    ];
30	
31	    public function mount(): void
32	    {
33	        $this->loadTickets();
34	    }
35	
36	    public function updatedFilterStatus(): void
37	    {
38	        $this->loadTickets();
39	    }
40	
41	    public function openResolve(int $ticketId): void
42	    {
43	        $this->resolvingTicketId = $ticketId;
44	        $this->reasonCode = 'cash_verified';
45	        $this->receiptReference = '';
46	    }
47	
48	    public function cancelResolve(): void
49	    {
50	        $this->resolvingTicketId = null;
51	    }
52	
53	    public function resolveTicket(): void
54	    {
55	        $this->error = null;
56	        $this->message = null;
57	
58	        if (!$this->resolvingTicketId) {
59	            $this->error = 'No ticket selected.';
60	            return;
61	        }
62	
63	        if (!array_key_exists($this->reasonCode, $this->reasonCodes)) {
64	            $this->error = 'Invalid reason code.';
65	            return;
66	        }
67	
68	        $ticket = DB::table('incident_tickets')->find($this->resolvingTicketId);
69	        if (!$ticket || $ticket->status !== 'open') {
70	            $this->error = 'Ticket not found or already resolved.';
71	            return;
72	        }
73	
74	        DB::table('incident_tickets')->where('id', $this->resolvingTicketId)->update([
75	            'status' => 'resolved',
76	            'resolution_reason_code' => $this->reasonCode,
77	            'receipt_reference' => trim($this->receiptReference) ? Crypt::encryptString(trim($this->receiptReference)) : null,
78	            'resolved_by' => auth()->id(),
79	            'resolved_at' => now(),
80	            'updated_at' => now(),
81	        ]);
82	
83	        // If there's an associated payment_intent in reconciling status, mark it confirmed
84	        if ($ticket->payment_intent_id) {
85	            DB::table('payment_intents')
86	                ->where('id', $ticket->payment_intent_id)
87	                ->where('status', 'reconciling')
88	                ->update([
89	                    'status' => 'confirmed',
90	                    'updated_at' => now(),
91	                ]);
92	        }
93	
94	        $this->message = "Ticket #{$this->resolvingTicketId} resolved.";
95	        $this->resolvingTicketId = null;
96	        $this->loadTickets();
97	    }
98	
99	    public function dismissTicket(int $id): void
100	    {
101	        $this->error = null;
102	        DB::table('incident_tickets')->where('id', $id)->where('status', 'open')->update([
103	            'status' => 'dismissed',
104	            'resolved_by' => auth()->id(),
105	            'resolved_at' => now(),
106	            'updated_at' => now(),
107	        ]);
108	
109	        $this->message = "Ticket #{$id} dismissed.";
110	        $this->loadTickets();
111	    }
112	
113	    private function loadTickets(): void
114	    {
115	        $query = DB::table('incident_tickets')
116	            ->leftJoin('orders', 'incident_tickets.order_id', '=', 'orders.id')
117	            ->leftJoin('payment_intents', 'incident_tickets.payment_intent_id', '=', 'payment_intents.id')
118	            ->leftJoin('users as assignee', 'incident_tickets.assigned_to', '=', 'assignee.id')
119	            ->leftJoin('users as resolver', 'incident_tickets.resolved_by', '=', 'resolver.id')
120	            ->select([
121	                'incident_tickets.*',
122	                'orders.status as order_status',
123	                'payment_intents.amount as payment_amount',
124	                'payment_intents.reference as payment_reference',
125	                'payment_intents.status as payment_status',
126	                'assignee.name as assignee_name',
127	                'resolver.name as resolver_name',
128	            ])
129	            ->orderByDesc('incident_tickets.created_at');
130	
131	        if ($this->filterStatus !== 'all') {
132	            $query->where('incident_tickets.status', $this->filterStatus);
133	        }
134	
135	        $this->tickets = $query->limit(100)->get()->map(fn ($t) => (array) $t)->toArray();
136	    }
137	
138	    public function render()
139	    {
140	        return view('livewire.manager.reconciliation-queue');
141	    }
142	}
