5	namespace App\Application\Order;
6	
7	use App\Domain\Auth\StepUpVerifier;
8	use App\Domain\Order\OrderStateMachine;
9	use App\Domain\Order\OrderStatus;
10	use App\Domain\Order\Exceptions\InsufficientRoleException;
11	use Illuminate\Support\Facades\DB;
12	
13	class TransitionOrderUseCase
14	{
15	    public function __construct(
16	        private readonly OrderStateMachine $stateMachine,
17	        private readonly StepUpVerifier $stepUpVerifier,
18	    ) {}
19	
20	    /**
21	     * @return array The updated order data
22	     */
23	    public function execute(
24	        int $orderId,
25	        string $targetStatus,
26	        int $expectedVersion,
27	        string $actorRole,
28	        int $actorId,
29	        ?string $managerPin = null,
30	        ?string $managerPinHash = null,
31	        ?string $cancelReason = null,
32	    ): array {
33	        return DB::transaction(function () use ($orderId, $targetStatus, $expectedVersion, $actorRole, $actorId, $managerPin, $managerPinHash, $cancelReason) {
34	            // Lock the order row for update
35	            $order = DB::table('orders')->where('id', $orderId)->lockForUpdate()->first();
36	
37	            if (!$order) {
38	                throw new \App\Application\Exceptions\BusinessException('Order not found.', 'NOT_FOUND', 404);
39	            }
40	
41	            $currentStatus = OrderStatus::from($order->status);
42	            $target = OrderStatus::from($targetStatus);
43	
44	            // Check step-up if needed — only manager/administrator can satisfy step-up
45	            $stepUpVerified = false;
46	            if ($target === OrderStatus::Canceled && $currentStatus->requiresStepUpForCancel()) {
47	                if (!in_array($actorRole, ['manager', 'administrator'], true)) {
48	                    throw new InsufficientRoleException(
49	                        role: $actorRole,
50	                        action: "cancel order in {$currentStatus->value} state (manager/admin required)",
51	                        requiredRoles: ['manager', 'administrator'],
52	                        requiresPin: true,
53	                    );
54	                }
55	                if (!$managerPin || !$managerPinHash) {
56	                    throw new InsufficientRoleException(
57	                        role: $actorRole,
58	                        action: "cancel order in {$currentStatus->value} state",
59	                        requiredRoles: ['manager', 'administrator'],
60	                        requiresPin: true,
61	                    );
62	                }
63	                if (!$this->stepUpVerifier->verify($managerPin, $managerPinHash)) {
64	                    throw new InsufficientRoleException(
65	                        role: $actorRole,
66	                        action: "cancel order (incorrect PIN)",
67	                        requiredRoles: ['manager', 'administrator'],
68	                        requiresPin: true,
69	                    );
70	                }
71	                $stepUpVerified = true;
72	
73	                // Log privilege escalation
74	                DB::table('privilege_escalation_logs')->insert([
75	                    'action' => 'cancel_' . $currentStatus->value,
76	                    'order_id' => $orderId,
77	                    'manager_id' => $actorId,
78	                    'manager_pin_hash' => $managerPinHash,
79	                    'reason' => $cancelReason,
80	                    'metadata' => json_encode(['from_status' => $currentStatus->value]),
81	                    'created_at' => now(),
82	                ]);
83	            }
84	
85	            // Enforce payment-confirmed prerequisite for settlement
86	            if ($target === OrderStatus::Settled) {
87	                $hasConfirmedPayment = DB::table('payment_intents')
88	                    ->where('order_id', $orderId)
89	                    ->where('status', 'confirmed')
90	                    ->exists();
91	
92	                if (!$hasConfirmedPayment) {
93	                    throw new \App\Domain\Order\Exceptions\PaymentRequiredException();
94	                }
95	            }
96	
97	            // Execute state machine transition
98	            $newVersion = $this->stateMachine->transition(
99	                $currentStatus,
100	                $target,
101	                (int) $order->version,
102	                $expectedVersion,
103	                $actorRole,
104	                $stepUpVerified,
105	            );
106	
107	            // Update order
108	            $updateData = [
109	                'status' => $target->value,
110	                'version' => $newVersion,
111	                'updated_at' => now(),
112	            ];
113	
114	            // Set actor fields
115	            match ($target) {
116	                OrderStatus::InPreparation => $updateData['confirmed_by'] = $actorId,
117	                OrderStatus::Served => $updateData['served_by'] = $actorId,
118	                OrderStatus::Settled => $updateData['settled_by'] = $actorId,
119	                OrderStatus::Canceled => (function () use (&$updateData, $actorId, $cancelReason) {
120	                    $updateData['canceled_by'] = $actorId;
121	                    $updateData['cancel_reason'] = $cancelReason;
122	                })(),
123	                default => null,
124	            };
125	
126	            DB::table('orders')->where('id', $orderId)->update($updateData);
127	
128	            // Lock items when moving to In Preparation
129	            if ($target === OrderStatus::InPreparation) {
130	                DB::table('order_items')
131	                    ->where('order_id', $orderId)
132	                    ->whereNull('locked_at')
133	                    ->update(['locked_at' => now()]);
134	            }
135	
136	            // Log status change
137	            DB::table('order_status_logs')->insert([
138	                'order_id' => $orderId,
139	                'from_status' => $currentStatus->value,
140	                'to_status' => $target->value,
141	                'changed_by' => $actorId,
142	                'version_at_change' => $newVersion,
143	                'metadata' => json_encode([
144	                    'cancel_reason' => $cancelReason,
145	                    'step_up_verified' => $stepUpVerified,
146	                ]),
147	                'created_at' => now(),
148	            ]);
149	
150	            // Track settled analytics event
151	            if ($target === OrderStatus::Settled) {
152	                (new \App\Application\Analytics\TrackEventUseCase())->execute(
153	                    eventType: 'order_settled',
154	                    payload: ['order_id' => $orderId, 'total' => (float) $order->total],
155	                );
156	            }
157	
158	            return (array) DB::table('orders')->find($orderId);
159	        });
160	    }
161	}
