56	                } catch (\Throwable) {
57	                    // Don't block search flow for logging failures
58	                }
59	
60	                $trending = $this->menuRepository->getTrendingTerms();
61	                return [
62	                    'items' => [],
63	                    'total' => 0,
64	                    'trending' => $trending,
