11	class EloquentMenuRepository implements MenuRepositoryInterface
12	{
13	    private function isPostgres(): bool
14	    {
15	        return DB::getDriverName() === 'pgsql';
16	    }
17	
18	    public function search(SearchQuery $query, array $allergenExclusions = []): array
19	    {
20	        $builder = DB::table('menu_items')
21	            ->join('menu_categories', 'menu_items.menu_category_id', '=', 'menu_categories.id')
22	            ->where('menu_items.is_active', true)
23	            ->where('menu_categories.is_active', true);
24	
25	        // Full-text search
26	        if ($query->hasKeyword()) {
27	            if ($this->isPostgres()) {
28	                $tsQuery = $this->buildTsQuery($query->keyword);
29	                $builder->whereRaw("menu_items.search_vector @@ to_tsquery('english', ?)", [$tsQuery]);
30	            } else {
31	                // SQLite fallback: LIKE-based search
32	                $keyword = '%' . $query->keyword . '%';
33	                $builder->where(function ($q) use ($keyword) {
34	                    $q->where('menu_items.name', 'like', $keyword)
35	                      ->orWhere('menu_items.description', 'like', $keyword);
36	                });
37	            }
38	        }
39	
40	        // Price range
41	        if ($query->priceMin !== null) {
42	            $builder->where('menu_items.price', '>=', $query->priceMin);
43	        }
44	        if ($query->priceMax !== null) {
45	            $builder->where('menu_items.price', '<=', $query->priceMax);
46	        }
47	
48	        // Category filter
49	        if ($query->categoryId !== null) {
50	            $builder->where('menu_items.menu_category_id', $query->categoryId);
51	        }
52	
53	        // Allergen exclusions (negative filters)
54	        foreach ($allergenExclusions as $exclusion) {
55	            $key = $exclusion['key'];
56	
57	            if (isset($exclusion['exclude_when_gt'])) {
58	                // Numeric comparison: exclude items where attribute > threshold
59	                $threshold = $exclusion['exclude_when_gt'];
60	                if ($this->isPostgres()) {
61	                    $builder->whereRaw(
62	                        "NOT (COALESCE((menu_items.attributes->>?)::numeric, 0) > ?)",
63	                        [$key, $threshold]
64	                    );
65	                } else {
66	                    $builder->whereRaw(
67	                        "NOT (COALESCE(CAST(json_extract(menu_items.attributes, ?) AS REAL), 0) > ?)",
68	                        ['$.' . $key, $threshold]
69	                    );
70	                }
71	            } else {
72	                $excludeWhen = $exclusion['exclude_when'];
73	
74	                if ($this->isPostgres()) {
75	                    $builder->whereRaw(
76	                        "NOT (menu_items.attributes @> ?::jsonb)",
77	                        [json_encode([$key => $excludeWhen])]
78	                    );
79	                } else {
80	                    // SQLite fallback: JSON extract
81	                    $jsonValue = $excludeWhen ? 'true' : 'false';
82	                    $builder->whereRaw(
83	                        "NOT (json_extract(menu_items.attributes, ?) = ?)",
84	                        ['$.' . $key, $jsonValue]
85	                    );
86	                }
87	            }
88	        }
89	
90	        // Get total before pagination
91	        $total = $builder->count();
92	
93	        // Sorting
94	        $selectColumns = [
95	            'menu_items.id',
96	            'menu_items.sku',
97	            'menu_items.name',
98	            'menu_items.description',
99	            'menu_items.price',
100	            'menu_items.tax_category',
101	            'menu_items.attributes',
102	            'menu_items.created_at',
103	            'menu_categories.name as category_name',
104	            'menu_categories.id as category_id',
105	        ];
106	
107	        if ($query->hasKeyword() && $query->sort === 'relevance' && $this->isPostgres()) {
108	            $tsQuery = $this->buildTsQuery($query->keyword);
109	            $selectColumns[] = DB::raw("ts_rank(menu_items.search_vector, to_tsquery('english', " . DB::getPdo()->quote($tsQuery) . ")) as relevance_score");
110	            $builder->orderByDesc('relevance_score');
111	        } else {
112	            match ($query->sort) {
113	                'newest' => $builder->orderByDesc('menu_items.created_at'),
114	                'price_asc' => $builder->orderBy('menu_items.price'),
115	                'price_desc' => $builder->orderByDesc('menu_items.price'),
116	                default => $builder->orderBy('menu_items.name'),
117	            };
118	        }
119	
120	        $items = $builder
121	            ->select($selectColumns)
122	            ->offset(($query->page - 1) * $query->perPage)
123	            ->limit($query->perPage)
124	            ->get()
125	            ->map(function ($item) {
126	                $item->attributes = is_string($item->attributes) ? json_decode($item->attributes, true) : $item->attributes;
127	                return (array) $item;
128	            })
129	            ->toArray();
130	
131	        return [
132	            'items' => $items,
133	            'total' => $total,
134	        ];
135	    }
136	
137	    public function getTrendingTerms(?int $locationId = null): array
138	    {
139	        $query = DB::table('trending_searches')
140	            ->orderBy('sort_order')
141	            ->limit(20);
142	
143	        if ($locationId !== null) {
144	            $query->where('location_id', $locationId);
145	        }
146	
147	        return $query->pluck('term')->toArray();
148	    }
149	
150	    public function getCategories(): array
151	    {
152	        return DB::table('menu_categories')
153	            ->where('is_active', true)
154	            ->orderBy('sort_order')
155	            ->get(['id', 'name'])
156	            ->map(fn ($c) => (array) $c)
157	            ->toArray();
158	    }
159	
160	    public function findById(int $id): ?array
161	    {
162	        $item = DB::table('menu_items')
163	            ->join('menu_categories', 'menu_items.menu_category_id', '=', 'menu_categories.id')
164	            ->where('menu_items.id', $id)
165	            ->where('menu_items.is_active', true)
166	            ->select([
167	                'menu_items.*',
168	                'menu_categories.name as category_name',
169	            ])
170	            ->first();
171	
172	        if (!$item) {
173	            return null;
174	        }
175	
176	        $item = (array) $item;
177	        $item['attributes'] = is_string($item['attributes']) ? json_decode($item['attributes'], true) : $item['attributes'];
178	        return $item;
179	    }
180	
181	    private function buildTsQuery(string $keyword): string
182	    {
183	        $words = preg_split('/\s+/', trim($keyword));
184	        $tsTerms = array_map(fn ($w) => preg_replace('/[^a-zA-Z0-9]/', '', $w) . ':*', $words);
185	        return implode(' & ', array_filter($tsTerms));
186	    }
187	}
