5	namespace App\Domain\Order;
6	
7	enum OrderStatus: string
8	{
9	    case PendingConfirmation = 'pending_confirmation';
10	    case InPreparation = 'in_preparation';
11	    case Served = 'served';
12	    case Settled = 'settled';
13	    case Canceled = 'canceled';
14	
15	    /**
16	     * Returns the valid next statuses from the current status.
17	     */
18	    public function transitions(): array
19	    {
20	        return match ($this) {
21	            self::PendingConfirmation => [self::InPreparation, self::Canceled],
22	            self::InPreparation => [self::Served, self::Canceled],
23	            self::Served => [self::Settled, self::Canceled],
24	            self::Settled => [], // Terminal
25	            self::Canceled => [], // Terminal
26	        };
27	    }
28	
29	    public function canTransitionTo(self $target): bool
30	    {
31	        return in_array($target, $this->transitions(), true);
32	    }
33	
34	    public function isTerminal(): bool
35	    {
36	        return empty($this->transitions());
37	    }
38	
39	    public function label(): string
40	    {
41	        return match ($this) {
42	            self::PendingConfirmation => 'Pending Confirmation',
43	            self::InPreparation => 'In Preparation',
44	            self::Served => 'Served',
45	            self::Settled => 'Settled',
46	            self::Canceled => 'Canceled',
47	        };
48	    }
49	
50	    /**
51	     * Roles allowed to trigger a transition TO this status.
52	     *
53	     * Workflow: Cashier confirms order (→InPreparation), Kitchen marks prepared
54	     * food as served (→Served), Cashier/Manager settles via payment confirmation
55	     * (→Settled). Kitchen does NOT confirm orders — their responsibility begins
56	     * after cashier confirmation, and ends when food is served.
57	     *
58	     * @return string[] Array of UserRole string values
59	     */
60	    public function allowedRoles(): array
61	    {
62	        return match ($this) {
63	            self::InPreparation => ['cashier', 'manager', 'administrator'],       // Cashier confirms
64	            self::Served => ['kitchen', 'manager', 'administrator'],              // Kitchen marks served
65	            self::Settled => ['cashier', 'manager', 'administrator'],             // Via payment confirmation only
66	            self::Canceled => ['cashier', 'manager', 'administrator'],            // Step-up PIN for in_preparation/served
67	            self::PendingConfirmation => [],                                       // Initial state (kiosk-created)
68	        };
69	    }
70	
71	    /**
72	     * Whether canceling FROM this status requires a manager PIN.
73	     */
74	    public function requiresStepUpForCancel(): bool
75	    {
76	        return match ($this) {
77	            self::InPreparation => true,
78	            self::Served => true,
79	            default => false,
80	        };
81	    }
