7	use App\Application\Order\TransitionOrderUseCase;
8	use App\Domain\Auth\StepUpVerifier;
9	use App\Domain\Payment\HmacSigner;
10	use App\Domain\Payment\Exceptions\ExpiredNonceException;
11	use App\Domain\Payment\Exceptions\ReplayedNonceException;
12	use App\Domain\Payment\Exceptions\TamperedSignatureException;
13	use Illuminate\Support\Facades\DB;
14	
15	class ConfirmPaymentUseCase
16	{
17	    public function __construct(
18	        private readonly HmacSigner $signer,
19	        private readonly StepUpVerifier $stepUpVerifier,
20	        private readonly TransitionOrderUseCase $transitionOrder,
21	    ) {}
22	
23	    /**
24	     * @return array{confirmation_id: int, order_status: string, idempotent: bool}
25	     */
26	    public function execute(
27	        string $reference,
28	        string $hmacSignature,
29	        string $nonce,
30	        string $method,
31	        int $confirmedBy,
32	        string $actorRole,
33	        int $expectedVersion,
34	        ?string $notes = null,
35	        ?string $managerPin = null,
36	        ?string $managerPinHash = null,
37	    ): array {
38	        return DB::transaction(function () use ($reference, $hmacSignature, $nonce, $method, $confirmedBy, $actorRole, $expectedVersion, $notes, $managerPin, $managerPinHash) {
39	            $intent = DB::table('payment_intents')
40	                ->where('reference', $reference)
41	                ->lockForUpdate()
42	                ->first();
43	
44	            if (!$intent) {
45	                throw new \App\Application\Exceptions\BusinessException('Payment intent not found.', 'NOT_FOUND', 404);
46	            }
47	
48	            // Idempotency check — if already confirmed, return existing
49	            if ($intent->status === 'confirmed') {
50	                $existingConfirmation = DB::table('payment_confirmations')
51	                    ->where('payment_intent_id', $intent->id)
52	                    ->first();
53	
54	                return [
55	                    'confirmation_id' => $existingConfirmation ? $existingConfirmation->id : 0,
56	                    'order_status' => 'settled',
57	                    'idempotent' => true,
58	                ];
59	            }
60	
61	            if ($intent->status === 'canceled') {
62	                throw new \App\Application\Exceptions\BusinessException('Payment intent was canceled.', 'PAYMENT_CANCELED', 422);
63	            }
64	
65	            if ($intent->status === 'failed') {
66	                throw new \App\Application\Exceptions\BusinessException('Payment intent has failed.', 'PAYMENT_FAILED', 422);
67	            }
68	
69	            // Check expiry
70	            if (now()->gt($intent->expires_at)) {
71	                DB::table('payment_intents')
72	                    ->where('id', $intent->id)
73	                    ->update(['status' => 'failed', 'updated_at' => now()]);
74	
75	                throw new ExpiredNonceException(config('harborbite.payment.hmac_expiry_seconds', 300));
76	            }
77	
78	            // Verify HMAC
79	            $this->signer->verify(
80	                $hmacSignature,
81	                [
82	                    'reference' => $reference,
83	                    'amount' => (float) $intent->amount,
84	                    'order_id' => (int) $intent->order_id,
85	                ],
86	                $nonce,
87	                (int) strtotime($intent->created_at),
88	            );
89	
90	            // Mark intent as confirmed
91	            DB::table('payment_intents')
92	                ->where('id', $intent->id)
93	                ->update(['status' => 'confirmed', 'updated_at' => now()]);
94	
95	            // Create confirmation record
96	            $confirmationId = DB::table('payment_confirmations')->insertGetId([
97	                'payment_intent_id' => $intent->id,
98	                'confirmed_by' => $confirmedBy,
99	                'method' => $method,
100	                'notes' => $notes ? encrypt($notes) : null,
101	                'created_at' => now(),
102	            ]);
103	
104	            // Fetch order for ambiguous check
105	            $order = DB::table('orders')
106	                ->where('id', $intent->order_id)
107	                ->lockForUpdate()
108	                ->first();
109	
110	            if (!$order) {
111	                throw new \App\Application\Exceptions\BusinessException('Associated order not found.', 'NOT_FOUND', 404);
112	            }
113	
114	            // Check for ambiguous settlement (amount mismatch or non-served status)
115	            $isAmbiguous = abs((float) $intent->amount - (float) $order->total) > 0.01
116	                || $order->status !== 'served';
117	
118	            if ($isAmbiguous) {
119	                // Only manager/administrator can approve ambiguous settlements
120	                if (!in_array($actorRole, ['manager', 'administrator'], true)) {
121	                    throw new \App\Application\Exceptions\BusinessException(
122	                        'Ambiguous settlement requires manager or administrator role.',
123	                        'FORBIDDEN',
124	                        403,
125	                    );
126	                }
127	
128	                if (!$managerPin || !$managerPinHash) {
129	                    throw new \App\Application\Exceptions\BusinessException(
130	                        'Ambiguous settlement requires manager PIN approval (amount mismatch or non-standard status).',
131	                        'STEP_UP_REQUIRED',
132	                        403,
133	                    );
134	                }
135	
136	                if (!$this->stepUpVerifier->verify($managerPin, $managerPinHash)) {
137	                    throw new \App\Application\Exceptions\BusinessException('Incorrect manager PIN for ambiguous settlement.', 'STEP_UP_FAILED', 403);
138	                }
139	
140	                DB::table('privilege_escalation_logs')->insert([
141	                    'action' => 'settle_ambiguous',
142	                    'order_id' => $order->id,
143	                    'manager_id' => $confirmedBy,
144	                    'manager_pin_hash' => $managerPinHash,
145	                    'reason' => $order->status !== 'served'
146	                        ? "Settlement from non-served status: {$order->status}"
147	                        : sprintf('Payment amount $%.2f does not match order total $%.2f', (float) $intent->amount, (float) $order->total),
148	                    'metadata' => json_encode([
149	                        'payment_reference' => $reference,
150	                        'intent_amount' => (float) $intent->amount,
151	                        'order_total' => (float) $order->total,
152	                        'order_status' => $order->status,
153	                    ]),
154	                    'created_at' => now(),
155	                ]);
156	            }
157	
158	            // Route settle through authoritative TransitionOrderUseCase
159	            // (enforces OrderStateMachine, expected_version, role checks)
160	            $this->transitionOrder->execute(
161	                orderId: (int) $order->id,
162	                targetStatus: 'settled',
163	                expectedVersion: $expectedVersion,
164	                actorRole: $actorRole,
165	                actorId: $confirmedBy,
166	            );
167	
168	            return [
169	                'confirmation_id' => $confirmationId,
170	                'order_status' => 'settled',
171	                'idempotent' => false,
172	            ];
173	        });
174	    }
