5	namespace App\Domain\Payment;
6	
7	use App\Domain\Payment\Exceptions\ExpiredNonceException;
8	use App\Domain\Payment\Exceptions\TamperedSignatureException;
9	use App\Domain\Payment\Exceptions\ReplayedNonceException;
10	
11	class HmacSigner
12	{
13	    public function __construct(
14	        private readonly string $key,
15	        private readonly int $expirySeconds = 300,
16	    ) {}
17	
18	    /**
19	     * Sign parameters with HMAC-SHA256.
20	     *
21	     * @return array{signature: string, nonce: string, timestamp: int}
22	     */
23	    public function sign(array $params, ?string $nonce = null): array
24	    {
25	        $nonce = $nonce ?? bin2hex(random_bytes(16));
26	        $timestamp = time();
27	
28	        $payload = $this->buildPayload($params, $nonce, $timestamp);
29	        $signature = hash_hmac('sha256', $payload, $this->key);
30	
31	        return [
32	            'signature' => $signature,
33	            'nonce' => $nonce,
34	            'timestamp' => $timestamp,
35	        ];
36	    }
37	
38	    /**
39	     * Verify HMAC signature.
40	     *
41	     * @throws TamperedSignatureException
42	     * @throws ExpiredNonceException
43	     */
44	    public function verify(string $signature, array $params, string $nonce, int $timestamp): bool
45	    {
46	        // Check expiry
47	        if (abs(time() - $timestamp) > $this->expirySeconds) {
48	            throw new ExpiredNonceException($this->expirySeconds);
49	        }
50	
51	        // Recompute signature
52	        $payload = $this->buildPayload($params, $nonce, $timestamp);
53	        $expected = hash_hmac('sha256', $payload, $this->key);
54	
55	        if (!hash_equals($expected, $signature)) {
56	            throw new TamperedSignatureException();
57	        }
58	
59	        return true;
60	    }
61	
62	    private function buildPayload(array $params, string $nonce, int $timestamp): string
63	    {
64	        // Sort params deterministically
65	        ksort($params);
66	        $paramString = http_build_query($params);
67	        return "{$paramString}|{$nonce}|{$timestamp}";
68	    }
69	
70	    public function getExpirySeconds(): int
71	    {
72	        return $this->expirySeconds;
73	    }
74	}
