9	use App\Domain\Order\Exceptions\KitchenLockException;
10	use App\Domain\Order\Exceptions\InsufficientRoleException;
11	
12	class OrderStateMachine
13	{
14	    /**
15	     * Validate and describe a state transition.
16	     *
17	     * @param OrderStatus $currentStatus Current order status
18	     * @param OrderStatus $targetStatus Desired status
19	     * @param int $currentVersion Current order version in DB
20	     * @param int $expectedVersion Version the client thinks is current
21	     * @param string $actorRole Role of the user attempting the transition
22	     * @param bool $stepUpVerified Whether manager PIN was verified
23	     *
24	     * @throws StaleVersionException
25	     * @throws InvalidTransitionException
26	     * @throws InsufficientRoleException
27	     *
28	     * @return int The new version number
29	     */
30	    public function transition(
31	        OrderStatus $currentStatus,
32	        OrderStatus $targetStatus,
33	        int $currentVersion,
34	        int $expectedVersion,
35	        string $actorRole,
36	        bool $stepUpVerified = false,
37	    ): int {
38	        // 1. Check version (optimistic concurrency)
39	        if ($currentVersion !== $expectedVersion) {
40	            throw new StaleVersionException(
41	                currentVersion: $currentVersion,
42	                expectedVersion: $expectedVersion,
43	                currentStatus: $currentStatus->value,
44	            );
45	        }
46	
47	        // 2. Check if transition is valid
48	        if (!$currentStatus->canTransitionTo($targetStatus)) {
49	            throw new InvalidTransitionException(
50	                from: $currentStatus->value,
51	                to: $targetStatus->value,
52	            );
53	        }
54	
55	        // 3. Check role authorization
56	        $allowedRoles = $targetStatus->allowedRoles();
57	        if (!empty($allowedRoles) && !in_array($actorRole, $allowedRoles, true)) {
58	            throw new InsufficientRoleException(
59	                role: $actorRole,
60	                action: "transition to {$targetStatus->value}",
61	                requiredRoles: $allowedRoles,
62	            );
63	        }
64	
65	        // 4. Check step-up for cancellation
66	        if ($targetStatus === OrderStatus::Canceled && $currentStatus->requiresStepUpForCancel()) {
67	            if (!$stepUpVerified) {
68	                throw new InsufficientRoleException(
69	                    role: $actorRole,
70	                    action: "cancel order in {$currentStatus->value} state",
71	                    requiredRoles: ['manager', 'administrator'],
72	                    requiresPin: true,
73	                );
74	            }
75	        }
76	
77	        // 5. Return incremented version
78	        return $currentVersion + 1;
79	    }
80	}
