5	namespace App\Livewire\Manager;
6	
7	use App\Application\Order\TransitionOrderUseCase;
8	use Illuminate\Support\Facades\Crypt;
9	use Illuminate\Support\Facades\DB;
10	use Livewire\Component;
11	
12	class ReconciliationQueue extends Component
13	{
14	    public array $tickets = [];
15	    public string $filterStatus = 'open';
16	
17	    // Resolve form
18	    public ?int $resolvingTicketId = null;
19	    public string $reasonCode = 'cash_verified';
20	    public string $receiptReference = '';
21	
22	    public ?string $message = null;
23	    public ?string $error = null;
24	
25	    public array $reasonCodes = [
26	        'cash_verified' => 'Cash Verified',
27	        'card_receipt_matched' => 'Card Receipt Matched',
28	        'pos_system_confirmed' => 'POS System Confirmed',
29	        'other' => 'Other',
30	    ];
31	
32	    public function mount(): void
33	    {
34	        $this->loadTickets();
35	    }
36	
37	    public function updatedFilterStatus(): void
38	    {
39	        $this->loadTickets();
40	    }
41	
42	    public function openResolve(int $ticketId): void
43	    {
44	        $this->resolvingTicketId = $ticketId;
45	        $this->reasonCode = 'cash_verified';
46	        $this->receiptReference = '';
47	    }
48	
49	    public function cancelResolve(): void
50	    {
51	        $this->resolvingTicketId = null;
52	    }
53	
54	    public function resolveTicket(): void
55	    {
56	        $this->error = null;
57	        $this->message = null;
58	
59	        if (!$this->resolvingTicketId) {
60	            $this->error = 'No ticket selected.';
61	            return;
62	        }
63	
64	        if (!array_key_exists($this->reasonCode, $this->reasonCodes)) {
65	            $this->error = 'Invalid reason code.';
66	            return;
67	        }
68	
69	        $ticket = DB::table('incident_tickets')->find($this->resolvingTicketId);
70	        if (!$ticket || $ticket->status !== 'open') {
71	            $this->error = 'Ticket not found or already resolved.';
72	            return;
73	        }
74	
75	        // If there's an associated payment_intent in reconciling status, mark it confirmed
76	        if ($ticket->payment_intent_id) {
77	            DB::table('payment_intents')
78	                ->where('id', $ticket->payment_intent_id)
79	                ->where('status', 'reconciling')
80	                ->update([
81	                    'status' => 'confirmed',
82	                    'updated_at' => now(),
83	                ]);
84	        }
85	
86	        // Transition the order to settled if it is still in served state
87	        $order = DB::table('orders')->find($ticket->order_id);
88	        if ($order && $order->status === 'served') {
89	            $hasConfirmedPayment = DB::table('payment_intents')
90	                ->where('order_id', $order->id)
91	                ->where('status', 'confirmed')
92	                ->exists();
93	
94	            if (!$hasConfirmedPayment) {
95	                $this->error = 'Cannot resolve: no confirmed payment intent exists for this order.';
96	                return;
97	            }
98	
99	            try {
100	                $transitionUseCase = app(TransitionOrderUseCase::class);
101	                $transitionUseCase->execute(
102	                    orderId: (int) $order->id,
103	                    targetStatus: 'settled',
104	                    expectedVersion: (int) $order->version,
105	                    actorRole: 'manager',
106	                    actorId: (int) auth()->id(),
107	                );
108	            } catch (\Throwable $e) {
109	                $this->error = 'Failed to settle order: ' . $e->getMessage();
110	                return;
111	            }
112	        }
113	
114	        DB::table('incident_tickets')->where('id', $this->resolvingTicketId)->update([
115	            'status' => 'resolved',
116	            'resolution_reason_code' => $this->reasonCode,
117	            'receipt_reference' => trim($this->receiptReference) ? Crypt::encryptString(trim($this->receiptReference)) : null,
118	            'resolved_by' => auth()->id(),
119	            'resolved_at' => now(),
120	            'updated_at' => now(),
121	        ]);
122	
123	        $this->message = "Ticket #{$this->resolvingTicketId} resolved.";
124	        $this->resolvingTicketId = null;
125	        $this->loadTickets();
126	    }
127	
128	    public function dismissTicket(int $id): void
129	    {
130	        $this->error = null;
131	        DB::table('incident_tickets')->where('id', $id)->where('status', 'open')->update([
132	            'status' => 'dismissed',
133	            'resolved_by' => auth()->id(),
134	            'resolved_at' => now(),
135	            'updated_at' => now(),
136	        ]);
137	
138	        $this->message = "Ticket #{$id} dismissed.";
139	        $this->loadTickets();
140	    }
141	
142	    private function loadTickets(): void
143	    {
144	        $query = DB::table('incident_tickets')
145	            ->leftJoin('orders', 'incident_tickets.order_id', '=', 'orders.id')
146	            ->leftJoin('payment_intents', 'incident_tickets.payment_intent_id', '=', 'payment_intents.id')
147	            ->leftJoin('users as assignee', 'incident_tickets.assigned_to', '=', 'assignee.id')
148	            ->leftJoin('users as resolver', 'incident_tickets.resolved_by', '=', 'resolver.id')
149	            ->select([
150	                'incident_tickets.*',
151	                'orders.status as order_status',
152	                'payment_intents.amount as payment_amount',
153	                'payment_intents.reference as payment_reference',
154	                'payment_intents.status as payment_status',
155	                'assignee.name as assignee_name',
156	                'resolver.name as resolver_name',
157	            ])
158	            ->orderByDesc('incident_tickets.created_at');
159	
160	        if ($this->filterStatus !== 'all') {
161	            $query->where('incident_tickets.status', $this->filterStatus);
162	        }
163	
164	        $this->tickets = $query->limit(100)->get()->map(fn ($t) => (array) $t)->toArray();
165	    }
166	
167	    public function render()
168	    {
169	        return view('livewire.manager.reconciliation-queue');
170	    }
171	}
