18	        private readonly HmacSigner $signer,
19	        private readonly StepUpVerifier $stepUpVerifier,
20	        private readonly TransitionOrderUseCase $transitionOrder,
21	    ) {}
22	
23	    /**
24	     * @return array{confirmation_id: int, order_status: string, idempotent: bool}
25	     */
26	    public function execute(
27	        string $reference,
28	        string $hmacSignature,
29	        string $nonce,
30	        string $method,
31	        int $confirmedBy,
32	        string $actorRole,
33	        int $expectedVersion,
34	        ?string $notes = null,
35	        ?string $managerPin = null,
36	        ?string $managerPinHash = null,
37	    ): array {
38	        return DB::transaction(function () use ($reference, $hmacSignature, $nonce, $method, $confirmedBy, $actorRole, $expectedVersion, $notes, $managerPin, $managerPinHash) {
39	            $intent = DB::table('payment_intents')
40	                ->where('reference', $reference)
41	                ->lockForUpdate()
42	                ->first();
43	
44	            if (!$intent) {
45	                throw new \App\Application\Exceptions\BusinessException('Payment intent not found.', 'NOT_FOUND', 404);
46	            }
47	
48	            // Idempotency check — if already confirmed, return existing
49	            if ($intent->status === 'confirmed') {
50	                $existingConfirmation = DB::table('payment_confirmations')
51	                    ->where('payment_intent_id', $intent->id)
52	                    ->first();
53	
54	                return [
55	                    'confirmation_id' => $existingConfirmation ? $existingConfirmation->id : 0,
56	                    'order_status' => 'settled',
57	                    'idempotent' => true,
58	                ];
59	            }
60	
61	            if ($intent->status === 'canceled') {
62	                throw new \App\Application\Exceptions\BusinessException('Payment intent was canceled.', 'PAYMENT_CANCELED', 422);
63	            }
64	
65	            if ($intent->status === 'failed') {
66	                throw new \App\Application\Exceptions\BusinessException('Payment intent has failed.', 'PAYMENT_FAILED', 422);
67	            }
68	
69	            // Check nonce replay — if this nonce was already consumed, reject
70	            if ($intent->nonce_used_at !== null) {
71	                throw new ReplayedNonceException();
72	            }
73	
74	            // Check expiry
75	            if (now()->gt($intent->expires_at)) {
76	                DB::table('payment_intents')
77	                    ->where('id', $intent->id)
78	                    ->update(['status' => 'failed', 'updated_at' => now()]);
79	
80	                throw new ExpiredNonceException(config('harborbite.payment.hmac_expiry_seconds', 300));
81	            }
82	
83	            // Verify HMAC using the persisted signed timestamp
84	            $signedAt = $intent->signed_at ?? (int) strtotime($intent->created_at);
85	            $this->signer->verify(
86	                $hmacSignature,
87	                [
88	                    'reference' => $reference,
89	                    'amount' => (float) $intent->amount,
90	                    'order_id' => (int) $intent->order_id,
91	                ],
92	                $nonce,
93	                $signedAt,
94	            );
95	
96	            // Mark nonce as consumed and intent as confirmed
97	            DB::table('payment_intents')
98	                ->where('id', $intent->id)
99	                ->update([
100	                    'status' => 'confirmed',
101	                    'nonce_used_at' => now(),
102	                    'updated_at' => now(),
103	                ]);
104	
105	            // Create confirmation record
106	            $confirmationId = DB::table('payment_confirmations')->insertGetId([
107	                'payment_intent_id' => $intent->id,
108	                'confirmed_by' => $confirmedBy,
109	                'method' => $method,
110	                'notes' => $notes ? encrypt($notes) : null,
111	                'created_at' => now(),
112	            ]);
113	
114	            // Fetch order for ambiguous check
115	            $order = DB::table('orders')
116	                ->where('id', $intent->order_id)
117	                ->lockForUpdate()
118	                ->first();
119	
120	            if (!$order) {
121	                throw new \App\Application\Exceptions\BusinessException('Associated order not found.', 'NOT_FOUND', 404);
122	            }
123	
124	            // Check for ambiguous settlement (amount mismatch or non-served status)
125	            $isAmbiguous = abs((float) $intent->amount - (float) $order->total) > 0.01
126	                || $order->status !== 'served';
127	
128	            if ($isAmbiguous) {
129	                // Only manager/administrator can approve ambiguous settlements
