141	                        'STEP_UP_REQUIRED',
142	                        403,
143	                    );
144	                }
145	
146	                if (!$this->stepUpVerifier->verify($managerPin, $managerPinHash)) {
147	                    throw new \App\Application\Exceptions\BusinessException('Incorrect manager PIN for ambiguous settlement.', 'STEP_UP_FAILED', 403);
148	                }
